# Design Area 7 — Governance: baseline Policy initiative for all landing zones

MG_SCOPE='/providers/Microsoft.Management/managementGroups/mg-corp'

# Create a custom Policy initiative (set) bundling all baseline governance rules
cat > baseline-initiative.json << 'ENDJSON'
{
  "properties": {
    "displayName": "ALZ Baseline Governance",
    "description": "Baseline policies for all Azure landing zone subscriptions",
    "policyDefinitions": [
      {
        "policyDefinitionId": "/providers/Microsoft.Authorization/policyDefinitions/0a914e76-4921-4c19-b460-a2d36003525a",
        "policyDefinitionReferenceId": "audit-vm-managed-disks"
      },
      {
        "policyDefinitionId": "/providers/Microsoft.Authorization/policyDefinitions/e56962a6-4747-49cd-b67b-bf8b01975c4c",
        "policyDefinitionReferenceId": "allowed-locations",
        "parameters": {
          "listOfAllowedLocations": {"value": ["eastus", "eastus2", "westus2"]}
        }
      },
      {
        "policyDefinitionId": "/providers/Microsoft.Authorization/policyDefinitions/83a86a26-fd1f-447c-b59d-e51f44264114",
        "policyDefinitionReferenceId": "deny-public-ip"
      }
    ]
  }
}
ENDJSON

az policy set-definition create \
  --name 'alz-baseline-governance' \
  --definitions @baseline-initiative.json \
  --management-group mg-corp

# Assign the initiative at the root MG (applies to every subscription in the tenant)
az policy assignment create \
  --name 'alz-baseline-governance' \
  --display-name 'ALZ Baseline Governance' \
  --policy-set-definition 'alz-baseline-governance' \
  --scope $MG_SCOPE \
  --identity-type SystemAssigned \
  --location eastus
